class Solution(object):
    def countPairs(self, nums):
        def neighbors(x):
            s = list(str(x))
            res = set([x])
            for i in range(len(s)):
                for j in range(i + 1, len(s)):
                    s[i], s[j] = s[j], s[i]
                    res.add(int("".join(s)))
                    s[i], s[j] = s[j], s[i]
            return res
        count = {}
        ans = 0
        for x in nums:
            for nb in neighbors(x):
                if nb in count:
                    ans += count[nb]
            count[x] = count.get(x, 0) + 1
        return ans
